#include <bits/stdc++.h>
using namespace std;
const int maxn=5e5;
int n,m,vis[maxn];
vector<int> e[maxn];
void dfs(int x){
	if(!vis[x]){
		vis[x]=1,cout<<x<<" ";
		sort(e[x].begin(),e[x].end());
		for(int i:e[x]){
			dfs(i);
		}
	}
}
void bfs(){
	queue<int> q;
	for(q.push(1),vis[1]=1;q.size();q.pop()){
		cout<<q.front()<<" ";
		for(int i:e[q.front()]){
			if(!vis[i]){
				q.push(i);
				vis[i]=1;
			}
		}
	}
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y;i<=m;i++){
		cin>>x>>y;
		e[x].push_back(y);
	}
	dfs(1);
	fill(vis+1,vis+2+n,0);
	cout<<"\n";
	bfs();
	return 0;
}
